document.addEventListener("DOMContentLoaded",function(){window.addEventListener("load",()=>{let o=getObject("#countdown"),d=getObject("#bp_countdown_days",o),c=getObject("#bp_countdown_hours",o),p=getObject("#bp_countdown_minutes",o),l=getObject("#bp_countdown_seconds",o),r=d.dataset.separator;var n=d.dataset.year,e=d.dataset.month,t=d.dataset.day,a=d.dataset.hour-d.dataset.offset,s=d.dataset.minute,u=d.dataset.second;let b=new Date(n,e-1,t,a,s,0).getTime(),_=setInterval(function(){var n=(new Date).getTime(),n=b-n,e=Math.floor(n/864e5),t=Math.floor(n%864e5/36e5),a=Math.floor(n%36e5/6e4),s=Math.floor(n%6e4/1e3);d.innerHTML="<span class='bp_countdown_number'>"+e+"</span><span class='bp_countdown_label'> day"+(1!==e?"s":"")+r+"</span>",c.innerHTML="<span class='bp_countdown_number'>"+t+"</span><span class='bp_countdown_label'> hour"+(1!==t?"s":"")+r+"</span>",p.innerHTML="<span class='bp_countdown_number'>"+a+"</span><span class='bp_countdown_label'> minute"+(1!==a?"s":"")+r+"</span>",l.innerHTML="<span class='bp_countdown_number'>"+s+"</span><span class='bp_countdown_label'> second"+(1!==s?"s":"")+"</span>",n<0&&(clearInterval(_),o.innerHTML="EXPIRED")},1e3)})});